def resume_training_from_checkpoint(checkpoint_path: str) -> dict:
    """
    Load a training checkpoint from the specified path and return its contents.

    Args:
        checkpoint_path: Path to the checkpoint file (.ckpt or .pth)

    Returns:
        Dictionary containing model state, optimizer state, and training metadata

    Raises:
        FileNotFoundError: If the checkpoint file does not exist
        ValueError: If the checkpoint file is invalid or corrupted
        TypeError: If the loaded data is not a dictionary
    """
    # Check if file exists
    if not os.path.exists(checkpoint_path):
        raise FileNotFoundError(f"Checkpoint file does not exist: {checkpoint_path}")

    try:
        # Attempt to load the checkpoint - Use weights_only=True for security
        checkpoint_data = torch.load(checkpoint_path, map_location='cpu', weights_only=True)
    except Exception as e:
        # If weights_only=True fails, try loading with weights_only=False for backward compatibility
        try:
            checkpoint_data = torch.load(checkpoint_path, map_location='cpu', weights_only=False)
        except Exception as e2:
            raise ValueError(f"Failed to load checkpoint file {checkpoint_path}: {str(e2)}")

    # Validate that the loaded data is a dictionary
    if not isinstance(checkpoint_data, dict):
        # If it's not a dict but appears to be valid model state, wrap it in a dict
        if hasattr(checkpoint_data, 'state_dict'):
            # It's likely a model instance, convert to state dict
            return {'model_state_dict': checkpoint_data.state_dict()}
        else:
            # For simple tensors or other objects, treat as model state
            return {'model_state_dict': checkpoint_data}

    # If the checkpoint is already in the correct format, return it
    # Or if it's just a state dict, wrap it appropriately
    if 'model_state_dict' not in checkpoint_data and 'optimizer_state_dict' not in checkpoint_data:
        # If the checkpoint is just a model state dict, wrap it properly
