            # Check if the content looks like a model state dict
            if any('weight' in str(k) or 'bias' in str(k) for k in checkpoint_data.keys()):
                return {'model_state_dict': checkpoint_data}

    # Ensure basic keys exist in the checkpoint
    required_keys = {'model_state_dict', 'optimizer_state_dict'}
    missing_keys = required_keys - set(checkpoint_data.keys())
    if missing_keys:
        # If only model_state_dict is missing, try to infer
        if 'model_state_dict' in missing_keys and len(missing_keys) == 1:
            # Check if the checkpoint itself is a state dict by checking for common tensor keys
            if any(isinstance(v, torch.Tensor) for v in checkpoint_data.values()):
                # Assume this is a model state dict
                return {'model_state_dict': checkpoint_data, 'optimizer_state_dict': {}}

        # If both required keys are missing, try to determine if the checkpoint is just a model state dict
        if 'model_state_dict' in missing_keys and 'optimizer_state_dict' in missing_keys:
            # If the loaded data looks like model weights (contains tensors with layer names), return it as model state
            if isinstance(checkpoint_data, dict) and any(
                isinstance(v, torch.Tensor) for v in checkpoint_data.values()
            ):
                return {'model_state_dict': checkpoint_data}
            else:
                # If we can't determine the type, still raise an error
                pass

    return checkpoint_data

